import React, { useState, useRef } from "react";
import "./App.css";
import weddingPhoto from "./wedding-photo.jpg";
// Décommentez la ligne ci-dessous si vous voulez remettre la musique
import weddingSong from "./wedding-song.mp3";

function App() {
  const [isOpen, setIsOpen] = useState(false);
  const audioRef = useRef(null);

  const handleOpenInvitation = () => {
    setIsOpen(true);
    if (audioRef.current) {
      audioRef.current.play();
    }
  };

  return (
    <div className="app-container">
      {/* <audio ref={audioRef} src={weddingSong} loop /> */}

      {/* ÉTAPE 1 : La lettre d'accueil */}
      {!isOpen ? (
        <div className="page-1-letter" onClick={handleOpenInvitation}>
          <div className="letter-content" onClick={(e) => e.stopPropagation()}>
            <h1 className="names-title">Elyes & Sarra</h1>
            <h2 className="subtitle">We are getting married</h2>
            <button className="open-button" onClick={handleOpenInvitation}>
              Click to open
            </button>
          </div>
        </div>
      ) : (
        /* ÉTAPE 2 : L'annonce avec la NOUVELLE photo complète */
        <div className="page-2-details">
          <img
            src={weddingPhoto}
            alt="Elyes et Sarra Wedding"
            className="full-image fade-in"
          />
        </div>
      )}
    </div>
  );
}

export default App;
